// Minimal reconciler showing the core idea:
function reconcile(parentDom, oldNode, newNode) {
  if (!oldNode) { parentDom.appendChild(create(newNode)); return; }
  if (!newNode) { parentDom.removeChild(oldNode._dom); return; }
  if (oldNode.type !== newNode.type) {
    parentDom.replaceChild(create(newNode), oldNode._dom);
    return;
  }
  // same type - patch props, recurse children
  patchProps(oldNode._dom, oldNode.props, newNode.props);
  reconcileChildren(oldNode._dom, oldNode.props.children, newNode.props.children);
}

