// Conceptual fiber loop (simplified from React source):
let nextUnitOfWork = null;
let wipRoot = null;

function workLoop(deadline) {
  while (nextUnitOfWork && deadline.timeRemaining() > 1) {
    nextUnitOfWork = performUnitOfWork(nextUnitOfWork);
  }
  if (nextUnitOfWork) {
    requestIdleCallback(workLoop); // resume later
  } else if (wipRoot) {
    commitRoot(); // commit synchronously - DOM mutations not interruptible
  }
}

function performUnitOfWork(fiber) {
  // 1. process this fiber (call component, diff props)
  if (!fiber.dom) fiber.dom = createDom(fiber);
  reconcileChildren(fiber, fiber.props.children);
  // 2. return next: child, then sibling, then up
  if (fiber.child) return fiber.child;
  let next = fiber;
  while (next) {
    if (next.sibling) return next.sibling;
    next = next.return;
  }
  return null;
}

