// Conceptual implementation
let currentFiber = null;
let hookIndex = 0;

function useState(initial) {
  const fiber = currentFiber;
  const idx = hookIndex++;
  if (!fiber.hooks[idx]) {
    fiber.hooks[idx] = { value: initial };
  }
  const hook = fiber.hooks[idx];
  const setState = (next) => {
    hook.value = typeof next === 'function' ? next(hook.value) : next;
    scheduleRerender(fiber);
  };
  return [hook.value, setState];
}

function render(Component, fiber) {
  currentFiber = fiber;
  hookIndex = 0; // reset - this is why call order matters
  if (!fiber.hooks) fiber.hooks = [];
  return Component(fiber.props);
}

