// Measuring a tooltip - MUST be useLayoutEffect
import { useLayoutEffect, useRef, useState } from 'react';

function Tooltip({ targetRect, children }: { targetRect: DOMRect; children: React.ReactNode }) {
  const ref = useRef<HTMLDivElement>(null);
  const [pos, setPos] = useState({ top: 0, left: 0 });
  useLayoutEffect(() => {
    const rect = ref.current!.getBoundingClientRect();
    // compute position to avoid overflow
    setPos({
      top: targetRect.bottom + 8,
      left: Math.min(targetRect.left, innerWidth - rect.width - 8),
    });
  }, [targetRect]);
  // setPos triggers a sync re-render BEFORE paint - user never sees wrong position
  return <div ref={ref} style={{ position: 'fixed', ...pos }}>{children}</div>;
}

// CSS-in-JS rule injection - useInsertionEffect
import { useInsertionEffect } from 'react';
function useCss(rule: string) {
  useInsertionEffect(() => {
    const style = document.createElement('style');
    style.textContent = rule;
    document.head.appendChild(style);
    return () => style.remove();
  }, [rule]);
  // Injected before any useLayoutEffect runs, so measurements see correct styles
