// Sketch of resilient realtime client
interface Event { id: string; seq: number; type: string; payload: any; }

class RealtimeClient {
  private lastSeq = 0;
  private buffer = new Map<number, Event>();
  private seen = new Set<string>();
  private state: AppState = initialState;

  onMessage(ev: Event) {
    if (this.seen.has(ev.id)) return; // dedupe
    this.seen.add(ev.id);
    this.buffer.set(ev.seq, ev);
    // apply in order, draining buffer
    while (this.buffer.has(this.lastSeq + 1)) {
      const next = this.buffer.get(this.lastSeq + 1)!;
      this.buffer.delete(this.lastSeq + 1);
      this.state = reduce(this.state, next);
      this.lastSeq = next.seq;
    }
  }

  onReconnect() {
    this.socket.send({ type: 'sync', from: this.lastSeq });
    // server replays missed events
  }

  optimistic(action: Action) {
    const tempId = crypto.randomUUID();
    this.state = reduce(this.state, { ...action, tempId });
    this.socket.send({ ...action, clientId: tempId });
  }
  onAck(tempId: string, realId: string) { /* swap tempId for realId */ }
  onReject(tempId: string) { /* rollback */ }
}

